  2	import NamespaceSafetyBox from '@odf/core/components/utils/safety-box';
  3	import { DiskSize } from '@odf/core/constants';
  4	import {
  5	  useODFNamespaceSelector,
  6	  useODFSystemFlagsSelector,
  7	} from '@odf/core/redux';
  8	import { StorageQuota } from '@odf/core/types';
  9	import {
 10	  ButtonBar,
 11	  fieldRequirementsTranslations,
 12	  formSettings,
 13	  getName,
 14	  StorageConsumerKind,
 15	  StorageConsumerModel,
 16	  TextInputWithFieldRequirements,
 17	  useCustomTranslation,
 18	  useDeepCompareMemoize,
 19	  useYupValidationResolver,
 20	} from '@odf/shared';
 21	import validationRegEx from '@odf/shared/utils/validation';
 22	import {
 23	  getAPIVersionForModel,
 24	  k8sCreate,
 25	  useK8sWatchResource,
 26	} from '@openshift-console/dynamic-plugin-sdk';
 27	import { Helmet } from 'react-helmet';
 28	import { useForm } from 'react-hook-form';
 29	import { useNavigate } from 'react-router-dom-v5-compat';
 30	import * as Yup from 'yup';
 31	import {
 32	  Form,
 33	  TextContent,
 34	  TextVariants,
 35	  Text,
 36	  ActionGroup,
 37	  Button,
 38	} from '@patternfly/react-core';
 39	import { StorageQuotaBody } from './onboarding-modal';
 40	
 41	const unlimitedQuota: StorageQuota = {
 42	  value: 0,
 43	  unit: null,
 44	};
 45	
 46	const useStorageConsumerFormSchema = () => {
 47	  const { t } = useCustomTranslation();
 48	  const [data] = useK8sWatchResource<StorageConsumerKind[]>({
 49	    groupVersionKind: {
 50	      group: StorageConsumerModel.apiGroup,
 51	      kind: StorageConsumerModel.kind,
 52	      version: StorageConsumerModel.apiVersion,
 53	    },
 54	    isList: true,
 55	  });
 56	  const unmemoizedNames = data?.map(getName);
 57	  const names = useDeepCompareMemoize(unmemoizedNames, true);
 58	
 59	  return React.useMemo(() => {
 60	    const fieldRequirements = [
 61	      fieldRequirementsTranslations.maxChars(t, 253),
 62	      fieldRequirementsTranslations.startAndEndName(t),
 63	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
 64	      fieldRequirementsTranslations.cannotBeUsedBeforeInNamespace(t),
 65	      fieldRequirementsTranslations.cannotBeEmpty(t),
 66	    ];
 67	    const nameSchema = Yup.object({
 68	      storageconsumerName: Yup.string()
 69	        .max(253, fieldRequirements[0])
 70	        .matches(
 71	          validationRegEx.startAndEndsWithAlphanumerics,
 72	          fieldRequirements[1]
 73	        )
 74	        .matches(
 75	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
 76	          fieldRequirements[2]
 77	        )
 78	        .test(
 79	          'unique-name',
 80	          fieldRequirements[3],
 81	          (value: string) => !names.includes(value)
 82	        )
 83	        .matches(validationRegEx.nonEmptyString, fieldRequirements[4]),
 84	    });
 85	    return { formSchema: nameSchema, fieldRequirements };
 86	  }, [names, t]);
 87	};
 88	
 89	const CreateStorageConsumer: React.FC = () => {
 90	  const [name, setName] = React.useState('');
 91	  const [progress, setProgress] = React.useState(false);
 92	  const [error, setError] = React.useState(null);
 93	  const [quota, setQuota] = React.useState<StorageQuota>(unlimitedQuota);
 94	
 95	  const { odfNamespace } = useODFNamespaceSelector();
 96	
 97	  const flags = useODFSystemFlagsSelector();
 98	  const clusterName = flags?.systemFlags?.[odfNamespace]?.odfSystemName;
 99	
100	  const navigate = useNavigate();
101	
102	  const { formSchema, fieldRequirements } = useStorageConsumerFormSchema();
103	  const resolver = useYupValidationResolver(formSchema);
104	  const { control, handleSubmit, watch } = useForm({
105	    ...formSettings,
106	    resolver,
107	  });
108	  const { t } = useCustomTranslation();
109	
110	  const storageConsumerName = watch('storageconsumerName');
111	  React.useEffect(() => {
112	    setName(storageConsumerName);
113	  }, [storageConsumerName, setName]);
114	
115	  const onSubmit = (_unused, event) => {
116	    event.preventDefault();
117	    const quotaInGib: number = (() => {
118	      if (quota.unit === DiskSize.Gi) {
119	        return Number(quota.value);
120	      } else {
121	        return Number(quota.value) * 1024;
122	      }
123	    })();
124	    setProgress(true);
125	    k8sCreate<StorageConsumerKind>({
126	      model: StorageConsumerModel,
127	      data: {
128	        apiVersion: getAPIVersionForModel(StorageConsumerModel),
129	        kind: StorageConsumerModel.kind,
130	        metadata: {
131	          name,
132	          namespace: odfNamespace,
133	        },
134	        spec: {
135	          storageQuotaInGiB: quotaInGib,
136	          storageClasses: [
137	            { name: `${clusterName}-ceph-rbd` },
138	            { name: `${clusterName}-cephfs` },
139	          ],
140	          volumeSnapshotClasses: [
141	            { name: `${clusterName}-rbdplugin-snapclass` },
142	            { name: `${clusterName}-cephfsplugin-snapclass` },
143	          ],
144	        },
145	      },
146	    })
147	      .then(() => {
148	        setProgress(false);
149	        navigate(-1);
150	      })
151	      .catch((err) => {
152	        setProgress(false);
153	        setError(err?.message || err);
154	      });
155	  };
156	
157	  const exampleTranslatedText = t('Example');
158	
159	  return (
160	    <div className="odf-m-pane__body odf-m-pane__form">
161	      <Helmet>
162	        <title>{t('Create StorageConsumer')}</title>
163	      </Helmet>
164	      <TextContent className="odf-m-pane__heading odf-m-pane__heading--baseline">
165	        <Text component={TextVariants.h1}>{t('Create StorageConsumer')}</Text>
166	      </TextContent>
167	      <NamespaceSafetyBox>
168	        <Form onSubmit={handleSubmit(onSubmit)}>
169	          <TextInputWithFieldRequirements
170	            control={control}
171	            fieldRequirements={fieldRequirements}
172	            popoverProps={{
173	              headerContent: t('Name requirements'),
174	              footerContent: `${exampleTranslatedText}: stark-lab-consumer`,
175	            }}
176	            formGroupProps={{
177	              label: t('StorageConsumer Name'),
178	              fieldId: 'storageconsumer-name',
179	              className: 'control-label',
180	            }}
181	            textInputProps={{
182	              id: 'storageconsumer-name',
183	              name: 'storageconsumerName',
184	              className: 'pf-v6-c-form-control',
185	              type: 'text',
186	              placeholder: t('stark-lab-storage-consumer'),
187	              'data-test': 'storage-consumer-name',
188	              isRequired: true,
189	            }}
190	          />
191	          <StorageQuotaBody quota={quota} setQuota={setQuota} />
192	          <ButtonBar errorMessage={error} inProgress={progress}>
193	            <ActionGroup className="pf-v6-c-form">
194	              <Button id="submit-btn" type="submit" variant="primary">
195	                {t('Create')}
196	              </Button>
197	              <Button onClick={() => navigate(-1)} variant="secondary">
198	                {t('Cancel')}
199	              </Button>
200	            </ActionGroup>
201	          </ButtonBar>
202	        </Form>
203	      </NamespaceSafetyBox>
204	    </div>
205	  );
206	};
207	
208	export default CreateStorageConsumer;

