 45	const useStorageConsumerFormSchema = () => {
 46	  const { t } = useCustomTranslation();
 47	  const [data] = useK8sWatchResource<StorageConsumerKind[]>({
 48	    groupVersionKind: {
 49	      group: StorageConsumerModel.apiGroup,
 50	      kind: StorageConsumerModel.kind,
 51	      version: StorageConsumerModel.apiVersion,
 52	    },
 53	    isList: true,
 54	  });
 55	  const unmemoizedNames = data?.map(getName);
 56	  const names = useDeepCompareMemoize(unmemoizedNames, true);
 57	
 58	  return React.useMemo(() => {
 59	    const fieldRequirements = [
 60	      fieldRequirementsTranslations.maxChars(t, 253),
 61	      fieldRequirementsTranslations.startAndEndName(t),
 62	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
 63	      fieldRequirementsTranslations.cannotBeUsedBeforeInNamespace(t),
 64	      fieldRequirementsTranslations.cannotBeEmpty(t),
 65	    ];
 66	    const nameSchema = Yup.object({
 67	      storageconsumerName: Yup.string()
 68	        .max(253, fieldRequirements[0])
 69	        .matches(
 70	          validationRegEx.startAndEndsWithAlphanumerics,
 71	          fieldRequirements[1]
 72	        )
 73	        .matches(
 74	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
 75	          fieldRequirements[2]
 76	        )
 77	        .test(
 78	          'unique-name',
 79	          fieldRequirements[3],
 80	          (value: string) => !names.includes(value)
 81	        )
 82	        .matches(validationRegEx.nonEmptyString, fieldRequirements[4]),
 83	    });
 84	    return { formSchema: nameSchema, fieldRequirements };
 85	  }, [names, t]);
 86	};
